def get_track_svg(race_name, team_color='#e10600', size=300):
    path = None
    for key in TRACK_MAPS:
        if key.lower() in race_name.lower():
            path = TRACK_MAPS[key]
            break
    if not path:
        path = 'M 30,60 C 30,30 70,15 100,15 C 130,15 170,30 170,60 C 170,90 130,105 100,105 C 70,105 30,90 30,60 Z'
    h = int(size * 0.65)
    return f'''<svg viewBox="0 0 200 130" xmlns="http://www.w3.org/2000/svg" width="{size}" height="{h}">
        <rect width="200" height="130" fill="#111111" rx="8"/>
        <path d="{path}" fill="none" stroke="#1a1a1a" stroke-width="14" stroke-linecap="round" stroke-linejoin="round"/>
        <path d="{path}" fill="none" stroke="#2a2a2a" stroke-width="10" stroke-linecap="round" stroke-linejoin="round"/>
        <path d="{path}" fill="none" stroke="#cccccc" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" opacity="0.9"/>
        <path d="{path}" fill="none" stroke="#e10600" stroke-width="0.8" stroke-dasharray="3,10" stroke-linecap="round" stroke-linejoin="round" opacity="0.25"/>
    </svg>'''

def get_weather_svg(air_temp, track_temp, size=80):
    if air_temp > 35:
        return f'''<svg viewBox="0 0 80 80" width="{size}" height="{size}" xmlns="http://www.w3.org/2000/svg">
            <circle cx="40" cy="40" r="18" fill="#FFD700" opacity="0.9"/>
            <g stroke="#FFD700" stroke-width="3" opacity="0.7">
                <line x1="40" y1="8" x2="40" y2="16"/><line x1="40" y1="64" x2="40" y2="72"/>
                <line x1="8" y1="40" x2="16" y2="40"/><line x1="64" y1="40" x2="72" y2="40"/>
                <line x1="17" y1="17" x2="23" y2="23"/><line x1="57" y1="57" x2="63" y2="63"/>
                <line x1="63" y1="17" x2="57" y2="23"/><line x1="23" y1="57" x2="17" y2="63"/>
            </g>
        </svg>'''
    elif air_temp > 25:
        return f'''<svg viewBox="0 0 80 80" width="{size}" height="{size}" xmlns="http://www.w3.org/2000/svg">
            <circle cx="32" cy="38" r="14" fill="#FFD700" opacity="0.7"/>
            <ellipse cx="48" cy="42" rx="20" ry="14" fill="#888" opacity="0.8"/>
            <ellipse cx="35" cy="48" rx="18" ry="12" fill="#999" opacity="0.7"/>
        </svg>'''
    else:
        return f'''<svg viewBox="0 0 80 80" width="{size}" height="{size}" xmlns="http://www.w3.org/2000/svg">
            <ellipse cx="40" cy="35" rx="22" ry="15" fill="#666" opacity="0.9"/>
            <ellipse cx="30" cy="40" rx="18" ry="12" fill="#777" opacity="0.8"/>
            <ellipse cx="52" cy="40" rx="16" ry="11" fill="#777" opacity="0.8"/>
            <g stroke="#88AAFF" stroke-width="2" opacity="0.8">
                <line x1="28" y1="55" x2="24" y2="68"/><line x1="38" y1="55" x2="34" y2="68"/>
                <line x1="48" y1="55" x2="44" y2="68"/><line x1="58" y1="55" x2="54" y2="68"/>
            </g>
        </svg>'''